def timestamp() -> str:
    return datetime.datetime.now().strftime("%Y%m%d_%H%M%S")

def detect_project_root() -> Path:
    root = Path.cwd()
    markers = ["src", "main.py", "pyproject.toml", "requirements.txt"]
    found = [m for m in markers if (root / m).exists()]
    if not found:
        print("[WARN] No standard Claire project markers found in this folder.")
        print("[WARN] Continuing because the installer can create the required paths.")
    return root

def backup_existing(root: Path, relative_path: str, backup_root: Path) -> None:
    target = root / relative_path
    if not target.exists():
        return
    backup_path = backup_root / relative_path
    backup_path.parent.mkdir(parents=True, exist_ok=True)
    shutil.copy2(target, backup_path)

def write_file(root: Path, relative_path: str, content: str) -> None:
    target = root / relative_path
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content, encoding="utf-8", newline="\n")

def install() -> None:
    root = detect_project_root()
    backup_root = root / "backups" / f"claire_v17_56_{timestamp()}"
    backup_root.mkdir(parents=True, exist_ok=True)

    print(f"[CLAIRE] Installing {VERSION} — {BUILD_NAME}")
    print(f"[CLAIRE] Project root: {root}")
    print(f"[CLAIRE] Backup root: {backup_root}")

    for relative_path in CONTENTS:
        backup_existing(root, relative_path, backup_root)

    for relative_path, content in CONTENTS.items():
        write_file(root, relative_path, content)
        print(f"[WRITE] {relative_path}")

    install_record = {
        "version": VERSION,
        "build_name": BUILD_NAME,
        "installed_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "backup_root": str(backup_root),
        "files_written": list(CONTENTS.keys()),
        "launcher_path": "src/frontend/command_center/modern/index.html",
        "rollback_note": "To rollback, copy files from backup_root back into the project root."
    }
    record_path = root / "data" / "build_manifests" / "v17.56_install_record.json"
    record_path.parent.mkdir(parents=True, exist_ok=True)
    record_path.write_text(json.dumps(install_record, indent=2), encoding="utf-8")
    print(f"[WRITE] {record_path.relative_to(root)}")

    print("")
    print("[DONE] Claire v17.56 Operating Environment Redesign Foundation installed.")
    print("[NEXT] Restart your server if it is running, then open the launcher/dashboard.")
    print("[PATH] src\\frontend\\command_center\\modern\\index.html")

if __name__ == "__main__":
    install()
